sys_script_include.description:
Returns an array of objects containing the currently active running transactions.
Note that the function gathers active transactions from all nodes and hence may run for a while - consider calling it from an asynchonous context.
If the transactions cannot be gathered from all nodes, returns false;

sys_script_include.script:
function GetActiveTransactions()
{
	var strExecutionTrackerId = RunScriptInGlobalScope(
		"var vct = new VClusterTransaction('v_cluster_transaction');"
		+"vct.deleteTransactions();"
		+"result = vct.informOtherNodes();"
		+"vct.refreshTransactions(GlideSession.get().getSessionID());");

	if (IsValidSysId(strExecutionTrackerId) == true)
	{
		WaitForTracker(strExecutionTrackerId,1);
	}
	else
	{
		return false;
	}

	var aTransactions = [];

	var grVCT = new GlideRecord('v_cluster_transaction');
	grVCT.query();
	while (grVCT.next() == true)
	{
		var transaction = Clone(grVCT);

		// Useless metadata
		delete transaction.sys_id;
		delete transaction.sys_meta;
		delete transaction.sys_mod_count;
		delete transaction.sys_tags;

		// The scope name is just wrong and hence misleading
		delete transaction.initial_scope_name; 
		delete transaction.scope_name; 

		// Date time refers to the moment the virtual transaction was identified, not started
		delete transaction.sys_created_on; 
		delete transaction.sys_updated_on; 

		var aKeys = GetKeys(transaction);
		for (var nKey = 0; nKey < aKeys.length; nKey++)
		{
			var strKey = aKeys[nKey];
			transaction[strKey] = StringReplace(transaction[strKey],'1970-01-01 ','');
		}

		aTransactions.push(transaction);
	}
	return aTransactions;
}
